mapper.select:
SELECT r.*, c.title as competition_title, u.real_name as student_name, u.student_id as student_id_str, t.name as team_name, c.fee FROM registration r LEFT JOIN competition c ON r.competition_id = c.id LEFT JOIN user u ON r.student_id = u.id LEFT JOIN team t ON r.team_id = t.id
AND r.competition_id = #{competitionId}
AND r.status = #{status}
ORDER BY r.registration_time DESC

mapper.update:
UPDATE registration
status = #{status}, audit_time = #{auditTime}, auditor_id = #{auditorId}, remark = #{remark},
WHERE id = #{id}
